// Module: Settings — CortexBuild Ultimate (User Management + Profile)
import { useState, useEffect } from 'react';
import {
  User, Users, Building2, Activity, Lock, Plus, Trash2, X,
  CheckCircle2, AlertTriangle, RefreshCw, Eye, EyeOff,
} from 'lucide-react';
import { toast } from 'sonner';
import { useAuth } from '../../context/AuthContext';
import { usersApi } from '../../services/api';
import { getToken, API_BASE } from '../../lib/supabase';

// ─── Types ────────────────────────────────────────────────────────────────────

type Tab = 'profile' | 'users' | 'company' | 'system';

interface UserRow {
  id: string;
  name: string;
  email: string;
  role: string;
  company?: string;
  phone?: string;
}

// ─── Role badge colours ───────────────────────────────────────────────────────

const ROLE_COLOURS: Record<string, string> = {
  super_admin:     'bg-red-500/20 text-red-400 border border-red-500/40',
  company_owner:   'bg-purple-500/20 text-purple-400 border border-purple-500/40',
  admin:           'bg-blue-500/20 text-blue-400 border border-blue-500/40',
  project_manager: 'bg-green-500/20 text-green-400 border border-green-500/40',
  field_worker:    'bg-yellow-500/20 text-yellow-400 border border-yellow-500/40',
  client:          'bg-gray-500/20 text-gray-400 border border-gray-500/40',
};

const ROLE_LABEL: Record<string, string> = {
  super_admin:     'Super Admin',
  company_owner:   'Company Owner',
  admin:           'Admin',
  project_manager: 'Project Manager',
  field_worker:    'Field Worker',
  client:          'Client',
};

const ALL_ROLES = ['super_admin','company_owner','admin','project_manager','field_worker','client'];

const ADMIN_ROLES = new Set(['super_admin','company_owner','admin','project_manager']);
const CAN_DELETE  = new Set(['super_admin','company_owner']);

function RoleBadge({ role }: { role: string }) {
  return (
    <span className={`inline-block px-2 py-0.5 rounded text-xs font-medium ${ROLE_COLOURS[role] ?? 'bg-gray-700 text-gray-300'}`}>
      {ROLE_LABEL[role] ?? role}
    </span>
  );
}

// ─── Create User Modal ────────────────────────────────────────────────────────

interface CreateUserModalProps {
  onClose: () => void;
  onCreated: (u: UserRow) => void;
}

function CreateUserModal({ onClose, onCreated }: CreateUserModalProps) {
  const [form, setForm] = useState({ name: '', email: '', password: '', role: 'field_worker', phone: '' });
  const [saving, setSaving] = useState(false);

  const set = (k: keyof typeof form) => (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) =>
    setForm(f => ({ ...f, [k]: e.target.value }));

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.name || !form.email || !form.password) {
      toast.error('Name, email, and password are required');
      return;
    }
    setSaving(true);
    try {
      const created = await usersApi.create(form as unknown as Record<string, unknown>);
      toast.success('User created successfully');
      onCreated(created as unknown as UserRow);
      onClose();
    } catch (err) {
      toast.error(err instanceof Error ? err.message : 'Failed to create user');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm">
      <div className="bg-gray-900 border border-gray-800 rounded-xl w-full max-w-md mx-4 shadow-2xl">
        <div className="flex items-center justify-between p-5 border-b border-gray-800">
          <h2 className="text-white font-semibold text-lg">Create New User</h2>
          <button onClick={onClose} className="text-gray-400 hover:text-white transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>
        <form onSubmit={handleSubmit} className="p-5 space-y-4">
          {/* Name */}
          <div>
            <label className="block text-sm text-gray-400 mb-1">Full Name *</label>
            <input
              value={form.name} onChange={set('name')} required
              placeholder="John Smith"
              className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white placeholder-gray-500 focus:outline-none focus:border-orange-500"
            />
          </div>
          {/* Email */}
          <div>
            <label className="block text-sm text-gray-400 mb-1">Email *</label>
            <input
              type="email" value={form.email} onChange={set('email')} required
              placeholder="john@example.com"
              className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white placeholder-gray-500 focus:outline-none focus:border-orange-500"
            />
          </div>
          {/* Password */}
          <div>
            <label className="block text-sm text-gray-400 mb-1">Password *</label>
            <input
              type="password" value={form.password} onChange={set('password')} required
              placeholder="••••••••"
              className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white placeholder-gray-500 focus:outline-none focus:border-orange-500"
            />
          </div>
          {/* Role */}
          <div>
            <label className="block text-sm text-gray-400 mb-1">Role *</label>
            <select
              value={form.role} onChange={set('role')}
              className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-orange-500"
            >
              {ALL_ROLES.map(r => (
                <option key={r} value={r}>{ROLE_LABEL[r]}</option>
              ))}
            </select>
          </div>
          {/* Phone */}
          <div>
            <label className="block text-sm text-gray-400 mb-1">Phone (optional)</label>
            <input
              value={form.phone} onChange={set('phone')}
              placeholder="+44 7700 900000"
              className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white placeholder-gray-500 focus:outline-none focus:border-orange-500"
            />
          </div>
          {/* Actions */}
          <div className="flex gap-3 pt-2">
            <button
              type="button" onClick={onClose}
              className="flex-1 py-2 rounded-lg border border-gray-700 text-gray-300 hover:bg-gray-800 transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit" disabled={saving}
              className="flex-1 py-2 rounded-lg bg-orange-500 hover:bg-orange-600 text-white font-medium transition-colors disabled:opacity-50"
            >
              {saving ? 'Creating…' : 'Create User'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

// ─── Tab: My Profile ──────────────────────────────────────────────────────────

function ProfileTab() {
  const { user, updateProfile } = useAuth();
  const [name, setName]   = useState(user?.name ?? '');
  const [phone, setPhone] = useState(user?.phone ?? '');
  const [savingProfile, setSavingProfile] = useState(false);

  const [currentPassword, setCurrentPassword] = useState('');
  const [newPassword, setNewPassword]         = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showCurrent, setShowCurrent]         = useState(false);
  const [showNew, setShowNew]                 = useState(false);
  const [savingPassword, setSavingPassword]   = useState(false);

  const handleProfileSave = async (e: React.FormEvent) => {
    e.preventDefault();
    setSavingProfile(true);
    try {
      await updateProfile({ name, phone });
      toast.success('Profile updated successfully');
    } catch (err) {
      toast.error(err instanceof Error ? err.message : 'Failed to update profile');
    } finally {
      setSavingProfile(false);
    }
  };

  const handlePasswordChange = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newPassword !== confirmPassword) {
      toast.error('New passwords do not match');
      return;
    }
    if (newPassword.length < 8) {
      toast.error('Password must be at least 8 characters');
      return;
    }
    setSavingPassword(true);
    try {
      const token = getToken();
      const res = await fetch(`${API_BASE}/auth/password`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({ currentPassword, newPassword }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.message || 'Password change failed');
      toast.success('Password changed successfully');
      setCurrentPassword('');
      setNewPassword('');
      setConfirmPassword('');
    } catch (err) {
      toast.error(err instanceof Error ? err.message : 'Failed to change password');
    } finally {
      setSavingPassword(false);
    }
  };

  return (
    <div className="space-y-6 max-w-xl">
      {/* Profile info */}
      <div className="bg-gray-900 border border-gray-800 rounded-xl p-6">
        <div className="flex items-center gap-3 mb-5">
          <div className="w-10 h-10 rounded-full bg-orange-500/20 flex items-center justify-center">
            <User className="w-5 h-5 text-orange-400" />
          </div>
          <div>
            <h2 className="text-white font-semibold">My Profile</h2>
            <p className="text-gray-400 text-sm">{user?.email}</p>
          </div>
          <div className="ml-auto">
            <RoleBadge role={user?.role ?? ''} />
          </div>
        </div>
        <form onSubmit={handleProfileSave} className="space-y-4">
          <div>
            <label className="block text-sm text-gray-400 mb-1">Full Name</label>
            <input
              value={name} onChange={e => setName(e.target.value)}
              className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-orange-500"
            />
          </div>
          <div>
            <label className="block text-sm text-gray-400 mb-1">Email</label>
            <input
              value={user?.email ?? ''} disabled
              className="w-full bg-gray-800/50 border border-gray-700 rounded-lg px-3 py-2 text-gray-500 cursor-not-allowed"
            />
          </div>
          <div>
            <label className="block text-sm text-gray-400 mb-1">Phone</label>
            <input
              value={phone} onChange={e => setPhone(e.target.value)}
              placeholder="+44 7700 900000"
              className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white placeholder-gray-500 focus:outline-none focus:border-orange-500"
            />
          </div>
          <button
            type="submit" disabled={savingProfile}
            className="w-full py-2 rounded-lg bg-orange-500 hover:bg-orange-600 text-white font-medium transition-colors disabled:opacity-50"
          >
            {savingProfile ? 'Saving…' : 'Save Profile'}
          </button>
        </form>
      </div>

      {/* Change password */}
      <div className="bg-gray-900 border border-gray-800 rounded-xl p-6">
        <div className="flex items-center gap-3 mb-5">
          <div className="w-10 h-10 rounded-full bg-gray-800 flex items-center justify-center">
            <Lock className="w-5 h-5 text-gray-400" />
          </div>
          <h2 className="text-white font-semibold">Change Password</h2>
        </div>
        <form onSubmit={handlePasswordChange} className="space-y-4">
          <div>
            <label className="block text-sm text-gray-400 mb-1">Current Password</label>
            <div className="relative">
              <input
                type={showCurrent ? 'text' : 'password'}
                value={currentPassword} onChange={e => setCurrentPassword(e.target.value)} required
                className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 pr-10 text-white focus:outline-none focus:border-orange-500"
              />
              <button type="button" onClick={() => setShowCurrent(s => !s)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-white">
                {showCurrent ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
              </button>
            </div>
          </div>
          <div>
            <label className="block text-sm text-gray-400 mb-1">New Password</label>
            <div className="relative">
              <input
                type={showNew ? 'text' : 'password'}
                value={newPassword} onChange={e => setNewPassword(e.target.value)} required
                className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 pr-10 text-white focus:outline-none focus:border-orange-500"
              />
              <button type="button" onClick={() => setShowNew(s => !s)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-white">
                {showNew ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
              </button>
            </div>
          </div>
          <div>
            <label className="block text-sm text-gray-400 mb-1">Confirm New Password</label>
            <input
              type="password"
              value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} required
              className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-orange-500"
            />
          </div>
          <button
            type="submit" disabled={savingPassword}
            className="w-full py-2 rounded-lg bg-orange-500 hover:bg-orange-600 text-white font-medium transition-colors disabled:opacity-50"
          >
            {savingPassword ? 'Updating…' : 'Change Password'}
          </button>
        </form>
      </div>
    </div>
  );
}

// ─── Tab: Users ───────────────────────────────────────────────────────────────

function UsersTab() {
  const { user } = useAuth();
  const [users, setUsers]           = useState<UserRow[]>([]);
  const [loading, setLoading]       = useState(true);
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [deletingId, setDeletingId] = useState<string | null>(null);

  const isAdmin      = ADMIN_ROLES.has(user?.role ?? '');
  const canDelete    = CAN_DELETE.has(user?.role ?? '');

  useEffect(() => {
    if (!isAdmin) { setLoading(false); return; }
    usersApi.getAll()
      .then(rows => setUsers(rows as unknown as UserRow[]))
      .catch(err => toast.error(err instanceof Error ? err.message : 'Failed to load users'))
      .finally(() => setLoading(false));
  }, [isAdmin]);

  const handleDelete = async (id: string) => {
    if (!window.confirm('Delete this user? This cannot be undone.')) return;
    setDeletingId(id);
    try {
      await usersApi.delete(id);
      setUsers(us => us.filter(u => u.id !== id));
      toast.success('User deleted');
    } catch (err) {
      toast.error(err instanceof Error ? err.message : 'Failed to delete user');
    } finally {
      setDeletingId(null);
    }
  };

  if (!isAdmin) {
    return (
      <div className="bg-gray-900 border border-gray-800 rounded-xl p-8 flex flex-col items-center gap-3 max-w-xl">
        <AlertTriangle className="w-8 h-8 text-yellow-400" />
        <p className="text-white font-medium">Only admins can manage users</p>
        <p className="text-gray-400 text-sm text-center">Contact your administrator to manage team members.</p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-white font-semibold text-lg">Team Members</h2>
          <p className="text-gray-400 text-sm">{users.length} user{users.length !== 1 ? 's' : ''}</p>
        </div>
        <button
          onClick={() => setShowCreateModal(true)}
          className="flex items-center gap-2 px-4 py-2 rounded-lg bg-orange-500 hover:bg-orange-600 text-white font-medium transition-colors"
        >
          <Plus className="w-4 h-4" />
          Add User
        </button>
      </div>

      {/* Table */}
      <div className="bg-gray-900 border border-gray-800 rounded-xl overflow-hidden">
        {loading ? (
          <div className="flex items-center justify-center py-16 gap-3 text-gray-400">
            <RefreshCw className="w-5 h-5 animate-spin" />
            Loading users…
          </div>
        ) : users.length === 0 ? (
          <div className="flex items-center justify-center py-16 text-gray-500">No users found</div>
        ) : (
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b border-gray-800 text-gray-400 text-xs uppercase tracking-wider">
                <th className="text-left px-5 py-3 font-medium">Name</th>
                <th className="text-left px-5 py-3 font-medium">Email</th>
                <th className="text-left px-5 py-3 font-medium">Role</th>
                {canDelete && <th className="px-5 py-3 w-16" />}
              </tr>
            </thead>
            <tbody>
              {users.map((u, i) => (
                <tr
                  key={u.id}
                  className={`border-b border-gray-800/50 hover:bg-gray-800/40 transition-colors ${i === users.length - 1 ? 'border-b-0' : ''}`}
                >
                  <td className="px-5 py-3">
                    <div className="flex items-center gap-3">
                      <div className="w-8 h-8 rounded-full bg-gray-700 flex items-center justify-center text-gray-300 font-medium text-xs">
                        {u.name.split(' ').map(p => p[0]).join('').slice(0,2).toUpperCase()}
                      </div>
                      <span className="text-white">{u.name}</span>
                      {u.id === user?.id && (
                        <span className="text-xs text-orange-400">(you)</span>
                      )}
                    </div>
                  </td>
                  <td className="px-5 py-3 text-gray-400">{u.email}</td>
                  <td className="px-5 py-3">
                    <RoleBadge role={u.role} />
                  </td>
                  {canDelete && (
                    <td className="px-5 py-3 text-right">
                      {u.id !== user?.id && (
                        <button
                          onClick={() => handleDelete(u.id)}
                          disabled={deletingId === u.id}
                          className="p-1.5 rounded text-gray-500 hover:text-red-400 hover:bg-red-500/10 transition-colors disabled:opacity-40"
                          title="Delete user"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      )}
                    </td>
                  )}
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {showCreateModal && (
        <CreateUserModal
          onClose={() => setShowCreateModal(false)}
          onCreated={u => setUsers(us => [...us, u])}
        />
      )}
    </div>
  );
}

