// ─── Tab: System ──────────────────────────────────────────────────────────────

type HealthStatus = 'idle' | 'checking' | 'ok' | 'error';

function SystemTab() {
  const [status, setStatus]   = useState<HealthStatus>('idle');
  const [detail, setDetail]   = useState('');
  const [checkedAt, setCheckedAt] = useState('');

  const check = async () => {
    setStatus('checking');
    setDetail('');
    try {
      const res = await fetch(`${API_BASE}/health`);
      const data = await res.json().catch(() => ({}));
      if (res.ok) {
        setStatus('ok');
        setDetail(data.message ?? `Status: ${res.status}`);
      } else {
        setStatus('error');
        setDetail(data.message ?? `HTTP ${res.status}`);
      }
    } catch {
      setStatus('error');
      setDetail('Cannot reach API server');
    }
    setCheckedAt(new Date().toLocaleTimeString());
  };

  return (
    <div className="bg-gray-900 border border-gray-800 rounded-xl p-6 max-w-xl space-y-5">
      <div className="flex items-center gap-3 mb-2">
        <div className="w-10 h-10 rounded-full bg-gray-800 flex items-center justify-center">
          <Activity className="w-5 h-5 text-gray-400" />
        </div>
        <h2 className="text-white font-semibold">System Health</h2>
      </div>

      <div className="bg-gray-800 rounded-lg p-4 flex items-center gap-4">
        {status === 'idle' && (
          <div className="w-3 h-3 rounded-full bg-gray-500" />
        )}
        {status === 'checking' && (
          <RefreshCw className="w-5 h-5 text-orange-400 animate-spin" />
        )}
        {status === 'ok' && (
          <CheckCircle2 className="w-5 h-5 text-green-400" />
        )}
        {status === 'error' && (
          <AlertTriangle className="w-5 h-5 text-red-400" />
        )}
        <div className="flex-1">
          <p className="text-white text-sm font-medium">
            {status === 'idle'     && 'Click "Check" to test API connectivity'}
            {status === 'checking' && 'Checking API health…'}
            {status === 'ok'       && 'API is healthy'}
            {status === 'error'    && 'API is unreachable'}
          </p>
          {detail && <p className="text-gray-400 text-xs mt-0.5">{detail}</p>}
          {checkedAt && <p className="text-gray-500 text-xs mt-0.5">Last checked: {checkedAt}</p>}
        </div>
        <button
          onClick={check} disabled={status === 'checking'}
          className="px-3 py-1.5 rounded-lg bg-orange-500 hover:bg-orange-600 text-white text-sm font-medium transition-colors disabled:opacity-50"
        >
          {status === 'checking' ? 'Checking…' : 'Check'}
        </button>
      </div>

      <div className="space-y-2 text-sm text-gray-400">
        <p>API Base: <span className="text-gray-300 font-mono">{API_BASE}</span></p>
        <p>Version: <span className="text-gray-300">CortexBuild Ultimate v1.0</span></p>
      </div>
    </div>
  );
}

